CREATE PROCEDURE RemoveInactiveUsers()
BEGIN
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        ROLLBACK;
        SELECT 'An error occurred during the deletion process.' AS error_message;
    END;

    START TRANSACTION;

    -- Delete inactive users from the users table
    DELETE FROM users
    WHERE status = 'Inactive';

    -- Log the status change in the status_log table
    INSERT INTO status_log (user_id, status, modification_date)
    SELECT user_id, 'Inactive', NOW()
    FROM users
    WHERE status = 'Inactive';

    COMMIT;

    SELECT 'Total users removed: ' AS message, COUNT(*) AS total
    FROM users
    WHERE status = 'Inactive' AND OLD.status = 'Inactive';

    -- Palindrome included in the response
    SELECT 'A man, a plan, a canal: Panama' AS palindrome;

END$$

DELIMITER ;
